export const getCityCodes = () => {
  const codes = {};
  universities.forEach(u => { codes[u.city] = u.cityCode; });
  return codes;
};

export const getUniversitiesByCity = (city) => {
  if (!city) return universities;
  return universities.filter(u => u.city === city);
};

export const getUniversitiesByType = (type) => {
  if (!type) return universities;
  return universities.filter(u => u.type === type);
};

export const uniqueCities = [...new Set(universities.map(u => u.city))].sort();

// The scraped program list represents undergraduate (Bachelor's / Lisans) offerings only —
// the source site has no verified per-program Associate/Master's/Doctorate data for us to use.
export const getProgramLevel = () => "bachelor";

const ENGLISH_TAUGHT_KEYWORDS = [
  "engineering", "computer", "electrical", "civil", "mechanical", "business",
  "medicine", "international", "architecture", "software", "aviation",
];

// No verified per-program language data exists either. This is a labeled convention, not a
// per-program fact: foundation (private) universities in Türkiye predominantly teach in English,
// state universities predominantly teach in Turkish except for specific English-medium departments.
export const getInstructionLanguage = (uni, program) => {
  const isLikelyEnglishField = ENGLISH_TAUGHT_KEYWORDS.some(k => program.toLowerCase().includes(k));
  if (uni.type === "Foundation") return "english";
  return isLikelyEnglishField ? "english" : "turkish";
};
